import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import './App.css';

function App() {
  const [prediction, setPrediction] = useState(null);
  const [worstCity, setWorstCity] = useState({ name: 'Loading...', avg_aqi: 0 });
  const [importance, setImportance] = useState([]);
  const [loading, setLoading] = useState(false);

  // Load Initial Intelligence
  useEffect(() => {
    // 1. Get Worst City Stats
    axios.get('http://127.0.0.1:8000/worst-city')
      .then(res => setWorstCity(res.data))
      .catch(err => console.error("Check if FastAPI is running on port 8000"));

    // 2. Get Feature Importance (Explainability)
    axios.get('http://127.0.0.1:8000/feature-impact')
      .then(res => {
        const formatted = Object.entries(res.data).map(([name, value]) => ({
          name, 
          value: parseFloat((value * 100).toFixed(2))
        })).sort((a, b) => b.value - a.value);
        setImportance(formatted);
      });
  }, []);

  const handlePredict = async () => {
    setLoading(true);
    try {
      // Mock data payload - in a full app, these come from Input forms
      const payload = {
        city: "Delhi", pm25: 110.5, pm10: 160.2, no: 18.1, no2: 28.3,
        nox: 35.0, co: 1.8, so2: 14.5, o3: 42.0, benzene: 1.5, toluene: 3.4, xylene: 1.2
      };
      const res = await axios.post('http://127.0.0.1:8000/predict?model_type=rf', payload);
      setPrediction(res.data);
    } catch (err) {
      alert("Backend Connection Failed!");
    }
    setLoading(false);
  };

  return (
    <div className="dashboard-container">
      <header className="dashboard-header">
        <h1>Air Quality Intelligence <span className="ai-badge">AI Powered</span></h1>
      </header>

      <div className="grid-layout">
        {/* Module 1: Prediction */}
        <section className="card prediction-card">
          <h2>Predictive Analysis</h2>
          <button className="predict-btn" onClick={handlePredict} disabled={loading}>
            {loading ? 'Analyzing...' : 'Run RF Prediction'}
          </button>

          {prediction && (
            <div className="result-area">
              <div className="aqi-value" style={{ color: prediction.color }}>
                {prediction.aqi}
              </div>
              <div className="aqi-category">{prediction.category}</div>
            </div>
          )}
        </section>

        {/* Module 2: Worst City Highlight */}
        <section className="card worst-city-card">
          <h2>Regional Insight</h2>
          <p>Worst Air Quality City (Avg)</p>
          <div className="city-name">{worstCity.name}</div>
          <div className="city-aqi">{worstCity.avg_aqi} AQI</div>
        </section>

        {/* Module 3: Explainability Chart */}
        <section className="card chart-card">
          <h2>Pollutant Contribution (Gini Importance)</h2>
          <div className="chart-container">
            <ResponsiveContainer width="100%" height={300}>
              <BarChart data={importance} layout="vertical">
                <XAxis type="number" hide />
                <YAxis dataKey="name" type="category" width={80} stroke="#94a3b8" />
                <Tooltip cursor={{fill: 'rgba(255,255,255,0.05)'}} />
                <Bar dataKey="value" radius={[0, 4, 4, 0]}>
                  {importance.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={index < 3 ? '#818cf8' : '#334155'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </section>
      </div>
    </div>
  );
}

export default App;
